2. **Configure Kafka Properties**
   Add the necessary properties in your `application.yml` or `application.properties`.

   Example `application.yml`:
   ```yaml
   spring:
     kafka:
       bootstrap-servers: localhost:9092
       group-id: order-group
       auto-offset-reset: earliest
       enable-auto-commit: false
       key-deserializer: org.apache.kafka.common.serialization.StringDeserializer
       value-deserializer: io.confluent.kafka.serializers.KafkaAvroDeserializer
       properties:
         schema.registry.url: http://localhost:8081
   ```

3. **Create Kafka Consumer Configuration**
   Create a configuration class to set up the Kafka consumer.

   ```java
   import org.apache.kafka.clients.consumer.ConsumerConfig;
   import org.apache.kafka.common.serialization.StringDeserializer;
   import io.confluent.kafka.serializers.KafkaAvroDeserializer;
   import org.springframework.context.annotation.Bean;
   import org.springframework.context.annotation.Configuration;
   import org.springframework.kafka.config.ConcurrentKafkaListenerContainerFactory;
   import org.springframework.kafka.core.DefaultKafkaConsumerFactory;

   @Configuration
   public class KafkaConsumerConfig {

       private final String bootstrapServers = "localhost:9092";
       private final String schemaRegistryUrl = "http://localhost:8081";

       @Bean
       public DefaultKafkaConsumerFactory<String, Object> consumerFactory() {
           Map<String, Object> configs = new HashMap<>();
           configs.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
           configs.put(ConsumerConfig.GROUP_ID_CONFIG, "order-group");
           configs.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
           configs.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, KafkaAvroDeserializer.class);
           configs.put("schema.registry.url", schemaRegistryUrl);

           return new DefaultKafkaConsumerFactory<>(configs);
       }

       @Bean
       public ConcurrentKafkaListenerContainerFactory<String, Object> kafkaListenerContainerFactory() {
           ConcurrentKafkaListenerContainerFactory<String, Object> factory = new ConcurrentKafkaListenerContainerFactory<>();
           factory.setConsumerFactory(consumerFactory());
           return factory;
       }
   }
   ```

4. **Create Kafka Consumer Service**
   Create a service class that uses the `ConcurrentKafkaListenerContainerFactory` to consume messages.

   ```java
   import org.springframework.kafka.annotation.KafkaListener;
   import org.springframework.stereotype.Service;

