public interface OutboxRepository extends JpaRepository<OutboxMessage, Long> {
}
```

4. **Background Job to Process Outbox Messages**
   - Create a background job or message consumer that reads from the outbox table and sends messages to Kafka.

```java
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

@Component
public class OutboxProcessor {

    private final KafkaTemplate<String, Object> kafkaTemplate;
    private final OutboxRepository outboxRepository;

    @Autowired
    public OutboxProcessor(KafkaTemplate<String, Object> kafkaTemplate,
                           OutboxRepository outboxRepository) {
        this.kafkaTemplate = kafkaTemplate;
        this.outboxRepository = outboxRepository;
    }

    @Scheduled(fixedRate = 60000) // Check every minute
    public void processOutbox() throws Exception {
        List<OutboxMessage> messages = outboxRepository.findByProcessed(false);
        for (OutboxMessage message : messages) {
            kafkaTemplate.send("order_events", message.getOrderId(), new ObjectMapper().readValue(message.getPayload(), OrderCreatedEvent.class));
            message.setProcessed(true);
            outboxRepository.save(message);
        }
    }
}
```

