import org.apache.flink.streaming.api.functions.AssignerWithPunctuatedWatermarks;
import org.apache.flink.streaming.api.windowing.time.Time;

public class OrderEventTimeAssigner implements AssignerWithPunctuatedWatermarks<OrderCreatedEvent> {

    @Override
    public long extractTimestamp(OrderCreatedEvent event) {
        // Extract the event timestamp from the event
        return event.getEventTimestamp();
    }

    @Override
    public Watermark generateWatermark(OrderCreatedEvent event) {
        // Generate watermarks based on the maximum observed event time plus a delay (e.g., 5 seconds)
        long watermark = System.currentTimeMillis() - 5000;
        if (watermark > extractTimestamp(event)) {
            return new Watermark(watermark);
        }
        return null;
    }
}
