import org.apache.avro.Schema;
import org.apache.avro.generic.GenericRecord;
import org.apache.avro.specific.SpecificDatumWriter;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.serialization.StringSerializer;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.serializer.JsonSerde;
import org.springframework.stereotype.Service;

@Service
public class OrderService {

    @Autowired
    private KafkaTemplate<String, GenericRecord> kafkaTemplate;

    @Autowired
    private SchemaRegistryClient schemaRegistryClient;

    public void createOrder(OrderRequest request) {
        // Business logic for creating an order
        Order order = new Order(request);

        String subject = "order-created-value";
        Schema schema = getSchema(subject);

        GenericRecord event = convertToAvro(order, schema);

        kafkaTemplate.send(new ProducerRecord<>("order-topic", "ORDER_CREATED", event));
    }

    private Schema getSchema(String subject) {
        return new CachedSchemaRegistryClient(schemaRegistryClient).getLatestSchemaMetadata(subject).getSchema();
    }

    private GenericRecord convertToAvro(Order order, Schema schema) {
        SpecificDatumWriter<GenericRecord> writer = new SpecificDatumWriter<>(schema);
        try (ByteArrayOutputStream out = new ByteArrayOutputStream()) {
            Encoder encoder = EncoderFactory.get().binaryEncoder(out, null);
            writer.write(order.toJson(), encoder);
            encoder.flush();
            return GenericData.fromJson(new String(out.toByteArray()));
        } catch (IOException e) {
            throw new RuntimeException("Failed to serialize order event", e);
        }
    }

    private String toJson(Order order) {
        try {
            return new ObjectMapper().writeValueAsString(order);
        } catch (JsonProcessingException e) {
            throw new RuntimeException("Failed to convert Order to JSON", e);
        }
    }
}
```

