import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaProducer;
import org.apache.flink.api.common.serialization.SimpleStringSchema;

public class FlinkJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set time characteristic to event-time processing
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        // Configure fixed delay restart strategy with 3 retries and 10-second delay between retries
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(3, Time.seconds(10)));

        // Kafka Consumer Configuration
        FlinkKafkaConsumer<String> kafkaConsumer = new FlinkKafkaConsumer<>(
                "order-topic",
                new SimpleStringSchema(),
                getProperties()
        );

        // Kafka Producer Configuration
        FlinkKafkaProducer<String> kafkaProducer = new FlinkKafkaProducer<>(
                "output-topic",
                new SimpleStringSchema(),
                getProperties(),
                FlinkKafkaProducer.Semantic.EXACTLY_ONCE
        );

        // Add your Flink job logic here
        DataStream<String> stream = env.addSource(kafkaConsumer);
        stream.map(new MapFunction<String, String>() {
            @Override
            public String map(String value) throws Exception {
                return "Processed: " + value;
            }
        }).addSink(kafkaProducer);

        // Execute the Flink job
        env.execute("Order Processing Job");
    }

    private static Properties getProperties() {
        Properties props = new Properties();
        props.setProperty("bootstrap.servers", "localhost:9092");
        props.setProperty("group.id", "flink-consumer-group");
        return props;
    }
}
```

