#### `OrderEventDeserializer.java`
```java
import org.apache.avro.Schema;
import org.apache.kafka.clients.consumer.ConsumerRecord;

public class OrderEventDeserializer implements MapFunction<String, OrderEvent> {

    @Autowired
    private SchemaRegistryClient schemaRegistryClient;

    @Override
    public OrderEvent map(String value) throws Exception {
        String subject = "order-created-value";
        Schema schema = getSchema(subject);

        GenericRecord orderEvent = convertFromAvro(value, schema);

        return new OrderEvent(orderEvent.get("event_type").toString(), (long) orderEvent.get("order_id"), (double) orderEvent.get("total"));
    }

    private Schema getSchema(String subject) {
        return new CachedSchemaRegistryClient(schemaRegistryClient).getLatestSchemaMetadata(subject).getSchema();
    }

    private GenericRecord convertFromAvro(String event, Schema schema) {
        try {
            SpecificDatumReader<GenericRecord> reader = new SpecificDatumReader<>(schema);
            Decoder decoder = DecoderFactory.get().jsonDecoder(schema, event);
            return reader.read(null, decoder);
        } catch (IOException e) {
            throw new RuntimeException("Failed to deserialize order event", e);
        }
    }
}
```

