    private KafkaTemplate<String, String> kafkaTemplate;

    @Autowired
    private DeadLetterPublishingRecoverer deadLetterPublishingRecoverer;

    public void consumeOrderMessages() {
        // Configure error handler to use DLQ
        SeekToCurrentErrorHandler errorHandler = new SeekToCurrentErrorHandler(
                deadLetterPublishingRecoverer, 
                new FixedBackOff(1000L, 3));

        KafkaListenerContainerFactory<ConcurrentMessageListenerContainer<String, String>> factory =
            kafkaListenerEndpoint().getKafkaListenerContainerFactory();

        factory.setErrorHandler(errorHandler);

        // Start consuming messages
        factory.createContainer(orderConsumer()).start();
    }

    @KafkaListener(topics = "order-topic", containerFactory = "kafkaListenerContainerFactory")
    public void listen(ConsumerRecord<String, String> record) {
        try {
            processOrder(record);
        } catch (Exception e) {
            // Log the error
            System.err.println("Error processing order: " + record.value());
            throw new RuntimeException(e); // Let the error handler handle it
        }
    }

    private void processOrder(ConsumerRecord<String, String> record) {
        // Logic to process the order message
        System.out.println("Processing order: " + record.value());

        // Simulate a failure
        if (record.key().equals("poison-pill")) {
            throw new RuntimeException("Poison pill detected");
        }
    }

    private KafkaListenerEndpoint<String, String> kafkaListenerEndpoint() {
        return new DefaultKafkaConsumerFactory<>(getKafkaProperties())
                .createReusableKafkaListenerContainerFactory()
                .kafkaListenerEndpoint();
    }

