#### Registering Schemas with Schema Registry in Spring Boot

1. **Order Service**:
   ```java
   @Service
   public class OrderService {

       private final KafkaTemplate<String, GenericRecord> kafkaTemplate;
       private final SchemaRegistryClient schemaRegistryClient;

       @Autowired
       public OrderService(KafkaTemplate<String, GenericRecord> kafkaTemplate, SchemaRegistryClient schemaRegistryClient) {
           this.kafkaTemplate = kafkaTemplate;
           this.schemaRegistryClient = schemaRegistryClient;
       }

       public void placeOrder(Order order) {
           // Validate the order
           if (!validateOrder(order)) return;

           try {
               // Register or retrieve schema for ORDER_PLACED event
               Schema orderPlacedSchema = getOrRegisterSchema("order_placed_topic", "ORDER_PLACED");

               // Create Avro record
               GenericRecord avroRecord = new GenericData.Record(orderPlacedSchema);
               avroRecord.put("event_type", "ORDER_PLACED");
               avroRecord.put("order_id", order.getId());
               avroRecord.put("customer_id", order.getCustomerId());
               avroRecord.put("items", createOrderItemsAvro(order.getItems()));
               avroRecord.put("total_amount", order.getTotalAmount());
               avroRecord.put("timestamp", System.currentTimeMillis());

               // Publish ORDER_PLACED event to Kafka
               kafkaTemplate.send("order_placed_topic", "ORDER_PLACED", avroRecord);
           } catch (Exception ex) {
               log.error("Failed to send ORDER_PLACED event for order: {}", order, ex);
               throw new OrderProcessingException("Failed to process the order", ex);
           }
       }

       private Schema getOrRegisterSchema(String subject, String eventType) throws IOException {
           // Check if schema already exists
           RegisteredSubject registered = schemaRegistryClient.getLatestVersion(subject + "-" + eventType);
           if (registered != null) {
               return new Schema.Parser().parse(registered.schema());
           }

           // Create and register the schema
           SchemaBuilder builder = SchemaBuilder.record("OrderPlacedEvent")
                   .fields()
                   .name("event_type").type().stringType().noDefault()
                   .name("order_id").type().stringType().noDefault()
                   .name("customer_id").type().stringType().noDefault()
                   .name("items").type().arrayOf(SchemaBuilder.record("OrderItem")
                           .fields()
                           .name("product_id").type().stringType().noDefault()
                           .name("quantity").type().intType().noDefault())
                   .noDefault()
                   .name("total_amount").type().doubleType().noDefault()
                   .name("timestamp").type().longType().noDefault();

           Schema schema = builder.endRecord();
           String id = schemaRegistryClient.register(subject + "-" + eventType, new SchemaAndVersion(schema));
           return schema;
       }

       private GenericData.Record[] createOrderItemsAvro(List<OrderItem> items) {
           List<GenericData.Record> avroRecords = new ArrayList<>();
           for (OrderItem item : items) {
               GenericData.Record avroItem = new GenericData.Record(new Schema.Parser().parse(
                       "{\"type\":\"record\",\"name\":\"OrderItem\",\"fields\":[{\"name\":\"product_id\",\"type\":\"string\"},{\"name\":\"quantity\",\"type\":\"int\"}]}"));
               avroItem.put("product_id", item.getProductId());
               avroItem.put("quantity", item.getQuantity());
               avroRecords.add(avroItem);
           }
           return avroRecords.toArray(new GenericData.Record[0]);
       }

       private boolean validateOrder(Order order) {
           // Validation logic here
           return true;
       }
   }
   ```

