        try (TransactionStatus status = new TransactionStatus()) {
            // Deserialize and process the event
            OrderPlacedEvent orderPlacedEvent = (OrderPlacedEvent) record.value();

            // Process the order in a database transaction
            processOrder(orderPlacedEvent);

            // Publish inventory update events if necessary
            kafkaTemplate.send("inventory_update_topic", "INVENTORY_DECREASED", createInventoryDecreaseEvent(orderPlacedEvent));

            // Commit both Kafka and database transactions
            status.commit();
        } catch (Exception ex) {
            log.error("Failed to process ORDER_PLACED event: {}", record, ex);
            throw new OrderProcessingException("Failed to process the order", ex);
        }
    }

    private void processOrder(OrderPlacedEvent orderPlacedEvent) {
        // Validate the order
        if (!validateOrder(orderPlacedEvent)) return;

        // Update the state in PostgreSQL
        Order savedOrder = orderRepository.save(new OrderEntity(orderPlacedEvent));

        // Send payment request to Payment Gateway Service
        kafkaTemplate.send("payment_received_topic", "PAYMENT_REQUESTED", createPaymentRequestEvent(savedOrder));
    }

    private boolean validateOrder(OrderPlacedEvent event) {
        // Validation logic here
        return true;
    }

    private GenericRecord createInventoryDecreaseEvent(OrderPlacedEvent event) {
        // Create and serialize inventory decrease event
        InventoryUpdateEvent inventoryDecreaseEvent = new InventoryUpdateEvent(event.getEventType(), event.getProduct_id(), event.getQuantity());
        return new GenericData.Record(inventoryDecreaseEvent);
    }

    private GenericRecord createPaymentRequestEvent(Order order) {
        // Create and serialize payment request event
        PaymentRequestedEvent paymentRequestEvent = new PaymentRequestedEvent(order.getOrder_id(), order.getTotal_amount());
        return new GenericData.Record(paymentRequestEvent);
    }
}
