### Saga Coordinator

The saga coordinator manages the sequence of steps and their compensating actions.

```java
@Service
public class SagaCoordinator {

    @Autowired
    private OrderService orderService;

    @Autowired
    private PaymentGatewayService paymentGatewayService;

    @Autowired
    private OrderConfirmationService orderConfirmationService;

    public void initiateOrderPlacement(Order order) {
        try {
            // Step 1: Place the order and decrease inventory
            orderService.placeOrder(order);

            // Step 2: Process payment
            Payment payment = new Payment(order);
            paymentGatewayService.processPayment(payment);

            // Step 3: Confirm the order
            orderConfirmationService.confirmOrder(order);
        } catch (Exception ex) {
            log.error("Failed to initiate order placement: {}", order, ex);
            rollbackSteps(order);
        }
    }

    private void rollbackSteps(Order order) {
        try {
            // Compensating action for step 3: Revert order confirmation
            orderConfirmationService.revertOrderConfirmation(order);

            // Compensating action for step 2: Refund payment
            paymentGatewayService.refundPayment(order);

            // Compensating action for step 1: Increase inventory
            orderService.increaseInventory(order);
        } catch (Exception ex) {
            log.error("Failed to rollback steps: {}", order, ex);
        }
    }

    public void increaseInventory(Order order) {
        try {
            kafkaTemplate.send("inventory_update_topic", "INVENTORY_INCREASED", createInventoryIncreaseEvent(order));
        } catch (Exception ex) {
            log.error("Failed to increase inventory for order: {}", order, ex);
        }
    }

    private String createInventoryIncreaseEvent(Order order) {
        // Create and serialize inventory increase event
        InventoryIncreasedEvent inventoryIncreasedEvent = new InventoryIncreasedEvent(order.getProductId(), order.getItems().stream()
                .map(item -> item.getQuantity()).reduce(Integer::sum).orElse(0));
        return new ObjectMapper().writeValueAsString(inventoryIncreasedEvent);
    }
}
```

