            kafkaTemplate.send("inventory_update_topic", "INVENTORY_INCREASED", createInventoryIncreaseEvent(event));
        } catch (Exception ex) {
            log.error("Failed to compensate INVENTORY_DECREASED for product: {}", event.getProduct_id(), ex);
            throw new InventoryManagementException("Failed to increase inventory", ex);
        }
