        this.schemaRegistryClient = schemaRegistryClient;
        this.sagaAuditRepository = sagaAuditRepository;
    }

    public void placeOrder(Order order) {
        try (TransactionStatus status = new TransactionStatus()) {
            // Step 1: Place order in the database
            Order savedOrder = orderRepository.save(new OrderEntity(order));

            // Step 2: Decrease inventory
            kafkaTemplate.send("inventory_update_topic", "INVENTORY_DECREASED", createInventoryDecreaseEvent(savedOrder));

            // Step 3: Request payment from the payment gateway
            kafkaTemplate.send("payment_received_topic", "PAYMENT_REQUESTED", createPaymentRequestEvent(savedOrder));

            status.commit();
