            // Trigger compensating actions if necessary
            try {
                sagaAuditRepository.save(createSagaAuditEntry(order.getId(), "INVENTORY_DECREASED", "FAILED"));
                kafkaTemplate.send("inventory_update_topic", "INVENTORY_INCREASED", createInventoryIncreaseEvent(order));
