                log.error("Failed to compensate INVENTORY_DECREASED for product: {}", order.getProduct_id(), compensateEx);
            }
            throw new OrderProcessingException("Failed to process the order", ex);
        }
    }

    private InventoryDecreasedEvent createInventoryDecreaseEvent(Order order) {
        // Create and serialize inventory decrease event
        return new InventoryDecreasedEvent(order.getEventType(), order.getProduct_id(), order.getQuantity());
    }

