        RegisteredSubject registered = schemaRegistryClient.getLatestVersion(subject + "-" + eventType);
        if (registered != null) {
            return new Schema.Parser().parse(registered.schema());
        }

        // Create and register the schema
        SchemaBuilder builder = SchemaBuilder.record("OrderPlacedEvent")
                .fields()
                .name("event_type").type().stringType().noDefault()
                .name("order_id").type().stringType().noDefault()
                .name("customer_id").type().stringType().noDefault()
                .name("items").type().arrayOf(SchemaBuilder.record("OrderItem")
                        .fields()
                        .name("product_id").type().stringType().noDefault()
                        .name("quantity").type().intType().noDefault())
                .noDefault()
                .name("total_amount").type().doubleType().noDefault()
                .name("timestamp").type().longType().noDefault();

        Schema schema = builder.endRecord();
        String id = schemaRegistryClient.register(subject + "-" + eventType, new SchemaAndVersion(schema));
        return schema;
    }

    private GenericData.Record[] createOrderItemsAvro(List<OrderItem> items) {
        List<GenericData.Record> avroRecords = new ArrayList<>();
        for (OrderItem item : items) {
            GenericData.Record avroItem = new GenericData.Record(new Schema.Parser().parse(
                    "{\"type\":\"record\",\"name\":\"OrderItem\",\"fields\":[{\"name\":\"product_id\",\"type\":\"string\"},{\"name\":\"quantity\",\"type\":\"int\"}]}"));
            avroItem.put("product_id", item.getProductId());
            avroItem.put("quantity", item.getQuantity());
            avroRecords.add(avroItem);
        }
        return avroRecords.toArray(new GenericData.Record[0]);
    }

    private boolean validateOrder(Order order) {
        // Validation logic here
        return true;
    }
}
