import org.springframework.retry.backoff.ExponentialBackOffPolicy;
import org.springframework.retry.policy.SimpleRetryPolicy;

@Configuration
public class RetryConfig {

    @Bean
    public SimpleRetryPolicy retryPolicy() {
        Map<Class<? extends Throwable>, Boolean> policies = new HashMap<>();
        policies.put(KafkaException.class, true);
        return new SimpleRetryPolicy(3, policies);
    }

    @Bean
    public ExponentialBackOffPolicy backoffPolicy() {
        ExponentialBackOffPolicy policy = new ExponentialBackOffPolicy();
        policy.setInitialInterval(1000); // Initial delay in milliseconds
        policy.setMaxInterval(5000);     // Maximum delay in milliseconds
        return policy;
    }
}
