import org.apache.flink.api.common.serialization.SimpleStringSchema;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;

public class FlinkJobConfig {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set time characteristic to event-time processing
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        // Configure restart strategy
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3, // Number of restart attempts
            Time.seconds(10) // Delay between restarts in seconds
        ));

        // Kafka consumer configuration
        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "inventory-group");

        FlinkKafkaConsumer<String> kafkaSource = new FlinkKafkaConsumer<>(
            "order_created",
            new SimpleStringSchema(),
            kafkaProps
        );

        // Define the stream processing logic
        DataStream<String> orderStream = env.addSource(kafkaSource);

        // Process the stream and adjust inventory levels
        orderStream.map(new InventoryAdjustmentFunction())
            .addSink(new KafkaProducer<>("inventory_adjusted", Order.class));

        // Execute the Flink job
        env.execute("Inventory Adjustment Job");
    }

    public static class InventoryAdjustmentFunction implements MapFunction<String, String> {
        @Override
        public String map(String value) throws Exception {
            // Adjust inventory levels based on the order
            adjustInventory(value);

            return value;
        }

        private void adjustInventory(String orderJson) {
            Order order = objectMapper.readValue(orderJson, Order.class);
            // Business logic for adjusting inventory levels
        }
    }

    public static class KafkaProducer<T> implements SinkFunction<T> {
        private final String topic;

        public KafkaProducer(String topic, Class<T> clazz) {
            this.topic = topic;
        }

        @Override
        public void invoke(T value, Context context) throws Exception {
            kafkaTemplate.send(topic, objectMapper.writeValueAsString(value));
        }
    }
}
```

