Handling event time and watermarks is crucial for ensuring accurate processing of real-time streams in Apache Flink. Event time refers to the timestamp associated with each event, which may differ from the processing time (the actual time when the event is processed). Watermarks are used to signal the progress of event time, allowing Flink to handle late events and ensure timely completion of stateful operations.

Here’s a step-by-step guide on how to handle event time and watermarks in your distributed order management system:

### 1. **Event Time Configuration**
Ensure that your Flink job is configured to use event time semantics.

#### Example `flink-conf.yaml`:
```yaml
# Set the default time characteristic to EventTime
state.ttl.default: 60m
```

### 2. **Assigning Timestamps and Watermarks**
When reading from Kafka, you need to assign timestamps to each record based on its event timestamp and generate watermarks.

#### Example Flink Job:
```java
import org.apache.flink.streaming.api.functions.AssignerWithPunctuatedWatermarks;
import org.apache.flink.streaming.api.watermark.Watermark;
import org.apache.kafka.clients.consumer.ConsumerRecord;

public class InventoryAdjustmentJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set time characteristic to event-time processing
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "inventory-group");

        FlinkKafkaConsumer<String> kafkaSource = new FlinkKafkaConsumer<>(
            "order_created",
            new SimpleStringSchema(),
            kafkaProps
        );

        // Define the stream processing logic
        DataStream<String> orderStream = env.addSource(kafkaSource)
                .assignTimestampsAndWatermarks(new OrderEventTimeAssigner());

        DataStream<Order> processedOrders = orderStream.map(new InventoryAdjustmentFunction())
                .keyBy(order -> order.getOrderId());

        processedOrders.addSink(new KafkaProducer<>("inventory_adjusted", Order.class));

        // Execute the Flink job
        env.execute("Inventory Adjustment Job");
    }

    public static class OrderEventTimeAssigner implements AssignerWithPunctuatedWatermarks<String> {
        private long currentMaxTimestamp = Long.MIN_VALUE;

        @Override
        public long extractTimestamp(String element, long previousElementTimestamp) {
            // Extract the event timestamp from the message payload (e.g., JSON)
            Order order = objectMapper.readValue(element, Order.class);
            return order.getEventTimestamp();
        }

        @Override
        public Watermark generateWatermark(String element) {
            currentMaxTimestamp = Math.max(currentMaxTimestamp, extractTimestamp(element, Long.MIN_VALUE));
            // Generate a watermark with a delay of 10 seconds to account for late events
            long watermarkDelay = 60 * 1000; // 1 minute delay
            return new Watermark(Math.max(Long.MIN_VALUE, currentMaxTimestamp - watermarkDelay));
        }
    }

    public static class InventoryAdjustmentFunction implements MapFunction<String, Order> {
        @Override
        public Order map(String value) throws Exception {
            try {
                // Adjust inventory levels based on the order
                adjustInventory(value);

                return objectMapper.readValue(value, Order.class);
            } catch (Exception e) {
                System.err.println("Failed to process order: " + e.getMessage());
                throw new RuntimeException(e);
            }
        }

        private void adjustInventory(String orderJson) {
            Order order = objectMapper.readValue(orderJson, Order.class);
            // Business logic for adjusting inventory levels
        }
    }

    public static class KafkaProducer<T> implements SinkFunction<T> {
        private final String topic;

        public KafkaProducer(String topic, Class<T> clazz) {
            this.topic = topic;
        }

        @Override
        public void invoke(T value, Context context) throws Exception {
            try {
                kafkaTemplate.send(topic, objectMapper.writeValueAsString(value));
            } catch (Exception e) {
                System.err.println("Failed to send message: " + e.getMessage());
                throw new RuntimeException(e);
            }
        }
    }
}
```

### 3. **Handling Late Events**
Late events are those that arrive after the watermark has passed their event time. You can handle late events by using side outputs or stateful operations like `ProcessFunction`.

#### Example Handling Late Events:
```java
import org.apache.flink.streaming.api.functions.ProcessFunction;
import org.apache.flink.util.Collector;

public class InventoryAdjustmentJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set time characteristic to event-time processing
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "inventory-group");

        FlinkKafkaConsumer<String> kafkaSource = new FlinkKafkaConsumer<>(
            "order_created",
            new SimpleStringSchema(),
            kafkaProps
        );

        // Define the stream processing logic
        DataStream<String> orderStream = env.addSource(kafkaSource)
                .assignTimestampsAndWatermarks(new OrderEventTimeAssigner());

        SingleOutputStreamOperator<Order> processedOrders = orderStream.map(new InventoryAdjustmentFunction())
                .keyBy(order -> order.getOrderId())
                .process(new LateOrderHandler());

        // Output the late events to a separate topic or sink
        processedOrders.getSideOutput(LateOrderHandler.LATE_OUTPUT_TAG).addSink(new KafkaProducer<>("late_order_events", Order.class));

        // Execute the Flink job
        env.execute("Inventory Adjustment Job");
    }

    public static class LateOrderHandler extends ProcessFunction<Order, Order> {
        public static final OutputTag<Order> LATE_OUTPUT_TAG = new OutputTag<Order>("late-orders") {};

        @Override
        public void processElement(Order order, Context context) throws Exception {
            if (context.timerService().currentWatermark() >= order.getEventTimestamp()) {
                // Process the event as usual
                adjustInventory(order);
                context.output(new OutputSelector<Order>() {
                    @Override
                    public String select(Order value) {
                        return "main-output";
                    }
                }, order);
            } else {
                // Handle late events
                System.err.println("Late event detected: " + order.getOrderId());
                context.output(LATE_OUTPUT_TAG, order);
            }
        }

        private void adjustInventory(Order order) {
            // Business logic for adjusting inventory levels
        }
    }
}
```

