@Component
public class OrderProducer {

    @Autowired
    private KafkaTemplate<String, Order> kafkaTemplate;

    public void sendOrder(Order order) {
        // Register the schema with the schema registry if not already registered
        registerSchema("order_created", Order.SCHEMA$);

        // Send event to Kafka topic
        kafkaTemplate.send("order_created", order);
    }

    private void registerSchema(String subject, Schema schema) {
        try {
            Integer id = kafkaTemplate.getProducerFactory().createProducer()
                .serializerForKey(KafkaAvroSerializer.class)
                .configure(Collections.singletonMap(
                    KafkaAvroSerializerConfig.SCHEMA_REGISTRY_URL_CONFIG,
                    "http://localhost:8081"
                ), false)
                .toSchema(schema);

            System.out.println("Registered schema with ID: " + id);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
```

