       }
   }

   public void registerSchemaWithCompatibility(String subject, String schemaString) {
       try {
           Integer id = kafkaTemplate.getProducerFactory().createProducer()
               .serializerForKey(KafkaAvroSerializer.class)
               .configure(Collections.singletonMap(
                   KafkaAvroSerializerConfig.SCHEMA_REGISTRY_URL_CONFIG,
                   "http://localhost:8081"
               ), false)
               .toSchema(new Schema.Parser().parse(schemaString), CompatibilityMode.BACKWARD_TRANSITIVE);

           System.out.println("Registered schema with ID and compatibility mode: " + id);
       } catch (Exception e) {
           throw new RuntimeException(e);
       }
   }
