#### Example Flink Job:
```java
public class InventoryAdjustmentJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "inventory-group");

        FlinkKafkaConsumer<String> kafkaSource = new FlinkKafkaConsumer<>(
            "order_created",
            new SimpleStringSchema(),
            kafkaProps
        );

        DataStream<String> orderStream = env.addSource(kafkaSource);

        // Process the stream and adjust inventory levels
        orderStream.map(new InventoryAdjustmentFunction())
                .addSink(new KafkaProducer<>("inventory_adjusted", Order.class));

        // Handle unprocessable messages by sending to DLQ
        orderStream.filter(message -> message == null || message.isEmpty())
                .map((MapFunction<String, String>) message -> "Failed message: " + message)
                .addSink(new KafkaProducer<>("order_created_dlq", String.class));

