        // Create a new Saga instance with initial state
        Saga saga = new Saga();
        saga.setSagaId(UUID.randomUUID().toString());
        saga.setCurrentStep(1);
        saga.setStatus("IN_PROGRESS");
        saga.setData(order);

        // Save the Saga to the database
        sagaRepository.save(saga);

        // Write audit entry before processing the first step
        writeAuditEntry(saga, "START", 0);

        try {
            switch (saga.getCurrentStep()) {
                case 1:
                    createOrder((Order) saga.getData());
                    saga.setCurrentStep(2);
                    break;
                case 2:
                    reserveInventory((Order) saga.getData());
                    saga.setCurrentStep(3);
                    break;
                case 3:
                    processPayment((Order) saga.getData());
                    saga.setCurrentStep(4);
                    break;
                case 4:
                    shipOrder((Order) saga.getData());
                    saga.setStatus("COMPLETED");
                    break;
                default:
                    throw new IllegalStateException("Unexpected value: " + saga.getCurrentStep());
            }
        } catch (Exception e) {
            // Handle failure and rollback
            saga.setStatus("FAILED");
            saga.setCurrentStep(saga.getCurrentStep() - 1);
            sagaRepository.save(saga);

            // Write audit entry before running compensation logic
            writeAuditEntry(saga, "FAIL", saga.getCurrentStep());

            if (saga.getCurrentStep() == 2) {
                releaseInventory((Order) saga.getData());
            } else if (saga.getCurrentStep() == 3) {
                refundPayment((Order) saga.getData());
            }
        }

