Integrating retries with the Dead-Letter Queue (DLQ) is crucial to ensure that unprocessable messages are handled gracefully. When a message fails after multiple retry attempts, it should be sent to the DLQ for further investigation or processing. Here’s how you can configure this interaction:

### 1. **Retry Configuration**
Configure your Kafka consumers to handle retries and send failed messages to the DLQ.

#### Example Retry Configuration:
```java
@Configuration
public class KafkaRetryConfig {

    @Bean
    public DefaultKafkaConsumerFactory<String, Order> consumerFactory() {
        Map<String, Object> configProps = new HashMap<>();
        configProps.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "${spring.kafka.bootstrap-servers}");
        configProps.put(ConsumerConfig.GROUP_ID_CONFIG, "inventory-group");
        configProps.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        configProps.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, JsonDeserializer.class);

        return new DefaultKafkaConsumerFactory<>(configProps);
    }

    @Bean
    public ConcurrentKafkaListenerContainerFactory<String, Order> kafkaListenerContainerFactory() {
        ConcurrentKafkaListenerContainerFactory<String, Order> factory = new ConcurrentKafkaListenerContainerFactory<>();
        factory.setConsumerFactory(consumerFactory());
        factory.getContainerProperties().setAckMode(ContainerProperties.AckMode.MANUAL_IMMEDIATE);

        // Configure retries
        factory.getContainerProperties().setRetryable(true);
        factory.getContainerProperties().getRetryTemplate().setBackOffPolicy(new ExponentialBackOffPolicy());
        factory.getContainerProperties().getRetryTemplate().setMaxAttempts(5);

        return factory;
    }

    @Bean
    public DefaultErrorHandler errorHandler() {
        DeadLetterPublishingRecoverer recoverer = new DeadLetterPublishingRecoverer(kafkaTemplate(), (record, e) -> {
            // Determine the appropriate DLQ topic based on error type or message content
            String dlqTopic = "order_created_dlq";
            return Optional.of(new TopicPartition(dlqTopic, 0));
        });

        return new DefaultErrorHandler(recoverer);
    }
}
```

